def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    avg_distances = np.array([
        np.mean([np.linalg.norm(truck_pos - customer) for truck_pos in all_truck_pos])
        for customer in unvisited_customers
    ])

    max_difference = -float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        cur_distance = np.linalg.norm(cur_truck_pos - customer)
        difference = avg_distances[i] - cur_distance

        if difference > max_difference:
            max_difference = difference
            best_node = i

    return best_node

